{
  "schema_version": 1,
  "request_id": "rf-suggest-edit-compressor-evidence-gap-partial-001",
  "project": "radishflow",
  "task": "suggest_flowsheet_edits",
  "status": "partial",
  "requires_confirmation": true,
  "answers": [
    {
      "summary": "当前围绕已选中的压缩机 compressor-1 的出口压力目标过近问题生成候选提案；由于诊断同时指出根因可能是压比不足或缺少下游背压数据，以下仅提供局部、可审查的占位式修改建议。",
      "issues": [
        {
          "title": "压缩机出口压力目标与入口压力过于接近",
          "details": "compressor-1 当前入口流股 feed-3 压力为 220 kPa，而机组出口压力目标仅为 235 kPa，直接触发“出口压力目标过近”的错误诊断。",
          "citations": [
            "diag-1",
            "flowdoc-unit-1",
            "flowdoc-stream-1"
          ]
        },
        {
          "title": "根因未确认，可能涉及压比不足或缺少下游背压信息",
          "details": "现有残差模式未能区分是压缩机目标压力设置不足，还是产品侧缺少必要压力规格，因此候选提案应限制为局部占位，避免未经证实的拓扑或大范围改动。",
          "citations": [
            "diag-2",
            "snapshot-1"
          ]
        }
      ],
      "proposed_actions": [
        {
          "action": "candidate_edit",
          "title": "为 compressor-1 的出口压力目标改为待确认占位值",
          "target": {
            "type": "unit",
            "id": "compressor-1"
          },
          "rationale": "错误诊断直接指向 compressor-1 的出口压力目标过近；将当前 235 kPa 替换为待确认占位，有助于把修订集中在被诊断对象上，同时不冒然假定具体目标压力。",
          "patch": {
            "parameter_placeholders": [
              {
                "path": "config.outlet_pressure_target_kpa",
                "expected_type": "number",
                "reason": "当前目标压力与 220 kPa 入口压力过近，需由用户确认更合适的出口压力目标。"
              }
            ]
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-1",
            "flowdoc-unit-1",
            "flowdoc-stream-1",
            "snapshot-1"
          ]
        },
        {
          "action": "candidate_edit",
          "title": "为 product-3 增加下游背压规格占位",
          "target": {
            "type": "stream",
            "id": "product-3"
          },
          "rationale": "警告诊断明确指出也可能是缺少下游背压数据导致残差模式异常；在不改动连接关系的前提下，为压缩机出口流股添加压力规格占位，可作为审查性补充以确认根因。",
          "patch": {
            "spec_placeholders": [
              {
                "path": "specs.pressure_kpa",
                "expected_type": "number",
                "reason": "需要补充下游或出口侧压力信息，以判断是否为缺失背压数据而非单纯压比不足。"
              }
            ]
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-2",
            "flowdoc-stream-2",
            "snapshot-1"
          ]
        }
      ],
      "confidence": 0.78,
      "citations": [
        "diag-1",
        "diag-2",
        "flowdoc-unit-1",
        "flowdoc-stream-1",
        "flowdoc-stream-2",
        "snapshot-1"
      ]
    }
  ],
  "citations": [
    {
